#include <iostream>

using namespace std;

class BankAccount
{
private:
    double balance;

public:
    void setBalance(double amount)
    {
        if (amount >= 0) // control what's allowed in
        {
            balance = amount;
        }
    }

    double getBalance()
    {
        return balance;
    }
};

int main()
{
    BankAccount acc;
    acc.setBalance(1000);

    cout << acc.getBalance() << endl;

    return 0;
}

